        let studyStates = {};
        let starredCards = {};
        let currentFilter = 'all';
        let searchQuery = '';
        let currentStudyFilter = 'all';
        let studyMode = 'standard';

        function loadState() {
            const savedStates = localStorage.getItem('agronomia_study_states');
            if (savedStates) {
                studyStates = JSON.parse(savedStates);
            }
            const savedStars = localStorage.getItem('agronomia_starred_cards');
            if (savedStars) {
                starredCards = JSON.parse(savedStars);
            }
            
            cardsData.forEach(c => {
                const status = studyStates[c.id] || 'todo';
                const isStarred = !!starredCards[c.id];
                
                const cardEl = document.getElementById(`card_${c.id}`);
                if (cardEl) {
                    cardEl.setAttribute('data-status', status);
                    if (isStarred) {
                        cardEl.classList.add('starred');
                    } else {
                        cardEl.classList.remove('starred');
                    }
                }
            });
            
            updateTrackerStats();
            renderDashboardRoadmap();
        }

        function saveState() {
            localStorage.setItem('agronomia_study_states', JSON.stringify(studyStates));
            localStorage.setItem('agronomia_starred_cards', JSON.stringify(starredCards));
            updateTrackerStats();
            renderDashboardRoadmap();
            const cmap = document.getElementById('cmapOverlay');
            if (cmap && cmap.classList.contains('is-open') && typeof renderConceptMap === 'function') {
                renderConceptMap();
            }
        }

        function playUiSound(type) {
            switch (type) {
        
                // ✅ TASK COMPLETED (success)
                case 'done':
                    playAudioTone(1040, 'triangle', 0.09);
                    break;
        
                // 🔄 TASK NOT DONE / TOGGLE OFF
                case 'undone':
                    playAudioTone(440, 'sine', 0.09);
                    break;
        
                // ⭐ STAR / FAVORITE
                case 'star':
                    playAudioTone(780, 'square', 0.06);
                    break;
        
                // 🔍 REVEAL CARD / OPEN DETAILS
                case 'reveal':
                    playAudioTone(620, 'sine', 0.05);
                    break;
        
                // 🎚️ UI SLIDER / GENERIC FEEDBACK
                case 'soft':
                    playAudioTone(600, 'sine', 0.03);
                    break;
        
                // 📏 WIDTH SLIDER (low tone)
                case 'low':
                    playAudioTone(420, 'sine', 0.03);
                    break;
        
                // 🔘 PANEL OPEN
                case 'open':
                    playAudioTone(780, 'sine', 0.08);
                    break;
        
                // 🔘 PANEL CLOSE
                case 'close':
                    playAudioTone(520, 'sine', 0.08);
                    break;
        
                // 🎛️ CONFIRM / PRESET APPLY
                case 'confirm':
                    playAudioTone(880, 'triangle', 0.06);
                    break;
            }
        }
        window.setCardStatus = function(id, status) {
            studyStates[id] = status;
        
            const cardEl = document.getElementById(`card_${id}`);
            if (cardEl) {
                cardEl.setAttribute('data-status', status);
            }
        
            saveState();
        
            playUiSound(status === 'done' ? 'done' : 'undone');
        };

        window.toggleStar = function(id) {
            starredCards[id] = !starredCards[id];
            const cardEl = document.getElementById(`card_${id}`);
            if (cardEl) {
                cardEl.classList.toggle('starred');
            }
            saveState();
            playUiSound('star');
        };

        window.revealCard = function(id) {
            const cardEl = document.getElementById(`card_${id}`);
            if (cardEl) {
                cardEl.classList.remove('active-recall-hidden');
            }
            playUiSound('reveal');
        };

        // NB: the typography & layout panel (font size / reading width) is wired up
