        function getFormattedDate(date) {
            const yyyy = date.getFullYear();
            const mm = String(date.getMonth() + 1).padStart(2, '0');
            const dd = String(date.getDate()).padStart(2, '0');
            return `${yyyy}-${mm}-${dd}`;
        }

        let sessionsCalendar = {};
        try {
            const savedCal = localStorage.getItem('agronomia_sessions_calendar');
            if (savedCal) {
                sessionsCalendar = JSON.parse(savedCal);
            } else {
                // Seed legacy completed sessions into today
                const legacyCount = parseInt(localStorage.getItem('agronomia_completed_sessions') || '0');
                if (legacyCount > 0) {
                    const todayStr = getFormattedDate(new Date());
                    sessionsCalendar[todayStr] = legacyCount;
                    localStorage.setItem('agronomia_sessions_calendar', JSON.stringify(sessionsCalendar));
                }
            }
        } catch(e) {
            console.error("Error reading sessions calendar", e);
        }

        function recalculateTotalCompletedSessions() {
            let total = 0;
            for (let d in sessionsCalendar) {
                total += sessionsCalendar[d] || 0;
            }
            completedSessionsCount = total;
            localStorage.setItem('agronomia_completed_sessions', completedSessionsCount);
        }

        function calculateStudyStreak() {
            let streak = 0;
            const checkDate = new Date();
            
            const todayStr = getFormattedDate(checkDate);
            const yesterday = new Date(checkDate);
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayStr = getFormattedDate(yesterday);

            // If no sessions today and no sessions yesterday, streak is 0
            if (!(sessionsCalendar[todayStr] > 0) && !(sessionsCalendar[yesterdayStr] > 0)) {
                return 0;
            }

            // Start checking day-by-day backward
            let testDate = new Date(checkDate);
            // If today has no sessions but yesterday did, start check from yesterday
            if (!(sessionsCalendar[todayStr] > 0)) {
                testDate.setDate(testDate.getDate() - 1);
            }

            while (true) {
                const dateStr = getFormattedDate(testDate);
                if (sessionsCalendar[dateStr] > 0) {
                    streak++;
                    testDate.setDate(testDate.getDate() - 1);
                } else {
                    break;
                }
            }
            return streak;
        }

        function calculateWeeklyAverage(totalSessionsInPeriod) {
            return (totalSessionsInPeriod / 12).toFixed(1);
        }

        function calculateDailyRecord() {
            let maxVal = 0;
            for (let d in sessionsCalendar) {
                if (sessionsCalendar[d] > maxVal) {
                    maxVal = sessionsCalendar[d];
                }
            }
            return maxVal;
        }

        // Date degli esami da evidenziare nel calendario
        const EXAM_DATES = {
            '2026-06-24': 'Esame · 24 giugno 2026',
            '2026-07-22': 'Esame · 22 luglio 2026'
        };

        function nextExamInfo() {
            const today = new Date(); today.setHours(0,0,0,0);
            const upcoming = Object.keys(EXAM_DATES)
                .map(d => { const [y,m,dd]=d.split('-').map(Number); return {d, date:new Date(y, m-1, dd)}; })
                .filter(x => x.date >= today)
                .sort((a,b) => a.date - b.date)[0];
            if (!upcoming) return '';
            const days = Math.round((upcoming.date - today) / 86400000);
            const lbl = EXAM_DATES[upcoming.d].replace('Esame · ', '');
            if (days === 0) return `Esame oggi (${lbl})`;
            return `Prossimo esame tra ${days} giorn${days===1?'o':'i'} (${lbl})`;
        }

        function renderActivityGrid() {
            const grid = document.getElementById('activityGrid');
            const monthsRow = document.getElementById('activityMonthsRow');
            const activityLegend = document.getElementById('activityLegend');
            if (!grid || !monthsRow) return;

            grid.innerHTML = '';
            monthsRow.innerHTML = '';

            const today = new Date();
            const totalDays = 84; // 12 weeks * 7 days
            
            // Start calendar grid strictly from the 1st of the current month (now we are in May)
            const startDate = new Date(today.getFullYear(), today.getMonth(), 1);
            
            // Align start date to the first Monday of this month
            const dayOfWeek = startDate.getDay();
            if (dayOfWeek !== 1) {
                const daysToAdd = dayOfWeek === 0 ? 1 : 8 - dayOfWeek;
                startDate.setDate(startDate.getDate() + daysToAdd);
            }

            const monthNames = ["Gen", "Feb", "Mar", "Apr", "Mag", "Giu", "Lug", "Ago", "Set", "Ott", "Nov", "Dic"];
            
            // Build Month labels for each column (week)
            const monthLabels = Array(12).fill('');
            let lastMonthIndex = -1;

            const labelDate = new Date(startDate);
            for (let col = 0; col < 12; col++) {
                const currentMonthIndex = labelDate.getMonth();
                if (currentMonthIndex !== lastMonthIndex) {
                    monthLabels[col] = monthNames[currentMonthIndex];
                    lastMonthIndex = currentMonthIndex;
                }
                labelDate.setDate(labelDate.getDate() + 7);
            }

            monthLabels.forEach((label, col) => {
                if (label) {
                    const labelSpan = document.createElement('span');
                    labelSpan.textContent = label;
                    labelSpan.style.position = 'absolute';
                    const leftOffset = col * (14 + 4);
                    labelSpan.style.left = `${leftOffset}px`;
                    labelSpan.style.whiteSpace = 'nowrap';
                    monthsRow.appendChild(labelSpan);
                }
            });

            const tempDate = new Date(startDate);
            let totalSessionsInPeriod = 0;
            
            for (let i = 0; i < totalDays; i++) {
                const dateStr = getFormattedDate(tempDate);
                const count = sessionsCalendar[dateStr] || 0;
                totalSessionsInPeriod += count;

                let level = 0;
                if (count === 1) level = 1;
                else if (count === 2) level = 2;
                else if (count === 3) level = 3;
                else if (count > 3) level = 4;

                const isExamDay = !!EXAM_DATES[dateStr];

                const options = { day: 'numeric', month: 'short', year: 'numeric' };
                const humanDate = tempDate.toLocaleDateString('it-IT', options);

                let label = count === 0
                    ? `Nessuna sessione il ${humanDate}`
                    : `${count} sessione${count > 1 ? 'i' : ''} completata${count > 1 ? 'e' : ''} il ${humanDate}`;
                if (isExamDay) label = `${EXAM_DATES[dateStr]} — ${label}`;

                const cell = document.createElement('div');
                cell.className = 'activity-cell';

                const now = new Date();
                const today =
                    now.getFullYear() + '-' +
                    String(now.getMonth() + 1).padStart(2, '0') + '-' +
                    String(now.getDate()).padStart(2, '0');
                if (dateStr === today) {
                    cell.classList.add('today');
                }

                cell.classList.add(`level-${level}`);
                if (isExamDay) cell.classList.add('exam');
                cell.title = label;
                
                cell.addEventListener('click', () => {
                    const newCountStr = prompt(`Modifica sessioni per il giorno ${humanDate}:`, count);
                    if (newCountStr !== null) {
                        const newCount = parseInt(newCountStr);
                        if (!isNaN(newCount) && newCount >= 0) {
                            if (newCount === 0) {
                                delete sessionsCalendar[dateStr];
                            } else {
                                sessionsCalendar[dateStr] = newCount;
                            }
                            localStorage.setItem('agronomia_sessions_calendar', JSON.stringify(sessionsCalendar));
                            recalculateTotalCompletedSessions();
                            updateSessionsUI();
                            renderActivityGrid();
                            playAudioTone(900, 'sine', 0.1);
                        }
                    }
                });

                grid.appendChild(cell);
                tempDate.setDate(tempDate.getDate() + 1);
            }

            if (activityLegend) {
                let legend = `${totalSessionsInPeriod} sessioni nel periodo`;
                const nx = nextExamInfo();
                if (nx) legend = nx + ' · ' + legend;
                activityLegend.textContent = legend;
            }

            // Update metric elements
            const streak = calculateStudyStreak();
            const weeklyAvg = calculateWeeklyAverage(totalSessionsInPeriod);
            const record = calculateDailyRecord();

            const calStatStreak = document.getElementById('calStatStreak');
            const calStatWeeklyAvg = document.getElementById('calStatWeeklyAvg');
            const calStatRecord = document.getElementById('calStatRecord');

            if (calStatStreak) calStatStreak.textContent = `${streak} giorn${streak === 1 ? 'o' : 'i'}`;
            if (calStatWeeklyAvg) calStatWeeklyAvg.textContent = weeklyAvg;
            if (calStatRecord) calStatRecord.textContent = `${record} sess.`;
        }

        function updateSessionsUI() {
            // Nel timer si mostrano le sessioni DI OGGI (il totale è nella dashboard).
            const todayStr = getFormattedDate(new Date());
            const todayCount = sessionsCalendar[todayStr] || 0;

            if (todayCount > 0) {
                minimizedSessionBadge.textContent = `x${todayCount}`;
                minimizedSessionBadge.style.display = 'inline-block';
            } else {
                minimizedSessionBadge.style.display = 'none';
            }

            if (todayCount === 0) {
                sessionsList.textContent = 'Nessuna';
            } else {
                sessionsList.textContent = todayCount === 1
                    ? '1 sessione'
                    : `${todayCount} sessioni`;
            }
        }

        const BASE_DOC_TITLE = document.title;

        // Lightweight non-blocking toast notification (replaces alert)
        let _toastTimer = null;
        function showToast(msg) {
            let t = document.getElementById('appToast');
            if (!t) {
                t = document.createElement('div');
                t.id = 'appToast';
                t.className = 'app-toast';
                t.setAttribute('role', 'status');
                document.body.appendChild(t);
            }
            t.textContent = msg;
            // force reflow so the transition re-triggers on repeated toasts
            void t.offsetWidth;
            t.classList.add('show');
            clearTimeout(_toastTimer);
            _toastTimer = setTimeout(() => t.classList.remove('show'), 4500);
        }

        function getActiveTimerMode() {
            return document.querySelector('.timer-mode-btn.active');
        }

        function updateTimerDisplay() {
            const minutes = Math.floor(timeLeft / 60);
            const seconds = timeLeft % 60;
            const txt = `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
            timerDisplay.textContent = txt;
            if (timerInterval) {
                const isStudy = !!document.querySelector('#modeStudy.active');
                document.title = `${txt} · ${isStudy ? 'Studio' : 'Pausa'} — Appunti`;
            } else {
                document.title = BASE_DOC_TITLE;
            }
        }

        function setTimerRunningUI(running) {
            pomodoroCard.classList.toggle('running', running);
            timerStartBtn.textContent = running ? 'Pausa' : 'Avvia';
        }

        function stopTimerInterval() {
            if (timerInterval) { clearInterval(timerInterval); timerInterval = null; }
        }

        function selectTimerMode(btn) {
            if (!btn) return;
            document.querySelectorAll('.timer-mode-btn').forEach(b => b.classList.toggle('active', b === btn));
            stopTimerInterval();
            setTimerRunningUI(false);
            timeLeft = parseInt(btn.getAttribute('data-time'));
            updateTimerDisplay();
        }

        function onTimerComplete() {
            stopTimerInterval();
            setTimerRunningUI(false);
            playAudioTone(880, 'sine', 0.8);

            const isStudyMode = getActiveTimerMode() && getActiveTimerMode().id === 'modeStudy';
            if (isStudyMode) {
                const todayStr = getFormattedDate(new Date());
                sessionsCalendar[todayStr] = (sessionsCalendar[todayStr] || 0) + 1;
                localStorage.setItem('agronomia_sessions_calendar', JSON.stringify(sessionsCalendar));
                recalculateTotalCompletedSessions();
                updateSessionsUI();
                renderActivityGrid();
                playAudioTone(1200, 'sine', 0.4);
            }

            // Auto-switch to the complementary mode, ready to start
            selectTimerMode(isStudyMode ? modeBreak : modeStudy);
            showToast(isStudyMode
                ? 'Sessione completata. Prenditi 5 minuti di pausa.'
                : 'Pausa finita. Pronto a riprendere lo studio.');
            document.title = BASE_DOC_TITLE;
        }

        function startTimer() {
            if (timerInterval) {
                stopTimerInterval();
                setTimerRunningUI(false);
                updateTimerDisplay();
                playAudioTone(440, 'sawtooth', 0.15);
            } else {
                setTimerRunningUI(true);
                playAudioTone(587, 'sine', 0.15);
                timerInterval = setInterval(() => {
                    if (timeLeft > 0) {
                        timeLeft--;
                        updateTimerDisplay();
                    } else {
                        onTimerComplete();
                    }
                }, 1000);
                updateTimerDisplay();
            }
        }

        function resetTimer() {
            stopTimerInterval();
            setTimerRunningUI(false);
            const currentMode = getActiveTimerMode();
            timeLeft = parseInt(currentMode.getAttribute('data-time'));
            updateTimerDisplay();
        }

        timerStartBtn.addEventListener('click', startTimer);
        timerResetBtn.addEventListener('click', resetTimer);
        modeStudy.addEventListener('click', () => selectTimerMode(modeStudy));
        modeBreak.addEventListener('click', () => selectTimerMode(modeBreak));

        // Collapsible/Floating Pomodoro Widget size actions
        timerToggleSizeBtn.addEventListener('click', (e) => {
            pomodoroCard.classList.add('minimized');
            playAudioTone(600, 'sine', 0.05);
            e.stopPropagation();
        });

        pomodoroCard.addEventListener('click', (e) => {
            if (pomodoroCard.classList.contains('minimized')) {
                pomodoroCard.classList.remove('minimized');
                playAudioTone(600, 'sine', 0.05);
            }
        });

        // Completed sessions adjust actions
        sessionIncBtn.addEventListener('click', (e) => {
            const todayStr = getFormattedDate(new Date());
            sessionsCalendar[todayStr] = (sessionsCalendar[todayStr] || 0) + 1;
            localStorage.setItem('agronomia_sessions_calendar', JSON.stringify(sessionsCalendar));
            recalculateTotalCompletedSessions();
            updateSessionsUI();
            renderActivityGrid();
            playAudioTone(800, 'sine', 0.05);
            e.stopPropagation();
        });

        sessionDecBtn.addEventListener('click', (e) => {
            const todayStr = getFormattedDate(new Date());
            if ((sessionsCalendar[todayStr] || 0) > 0) {
                sessionsCalendar[todayStr]--;
                if (sessionsCalendar[todayStr] === 0) {
                    delete sessionsCalendar[todayStr];
                }
                localStorage.setItem('agronomia_sessions_calendar', JSON.stringify(sessionsCalendar));
                recalculateTotalCompletedSessions();
                updateSessionsUI();
                renderActivityGrid();
                playAudioTone(500, 'sine', 0.05);
            }
            e.stopPropagation();
        });

        // Initialize session counter UI and activity calendar grid on load
        updateSessionsUI();
        renderActivityGrid();

        // ── TEMA ──────────────────────────────────────────────────────
        // Il tema iniziale è già stato applizato sul <html> dal boot script
        // (segue le impostazioni di sistema, o la scelta manuale salvata in
        // locale). Qui gestiamo solo il pulsante e l'ascolto del sistema.
        // Nota: la chiave 'theme' è esclusa dalla sincronizzazione KV
        // (vedi DEVICE_LOCAL in sync.js): resta una preferenza del dispositivo.
        const themeBtn = document.getElementById('themeBtn');

        function applyTheme(light) {
            if (light) {
                document.documentElement.setAttribute('data-theme', 'light');
            } else {
                document.documentElement.removeAttribute('data-theme');
            }
            if (window.MathJax && MathJax.typesetPromise) {
                MathJax.typesetPromise();
            }
        }

        if (themeBtn) {
            themeBtn.addEventListener('click', () => {
                const isLight = document.documentElement.getAttribute('data-theme') === 'light';
                const nextLight = !isLight;
                applyTheme(nextLight);
                try { localStorage.setItem('theme', nextLight ? 'light' : 'dark'); } catch (e) {}
            });
        }

        // Segue i cambi di tema di sistema, ma solo finché l'utente non ha
        // espresso una scelta manuale (che ha la precedenza, in locale).
        if (window.matchMedia) {
            const darkMq = window.matchMedia('(prefers-color-scheme: dark)');
            const onSystemThemeChange = (e) => {
                let saved = null;
                try { saved = localStorage.getItem('theme'); } catch (_) {}
                if (saved) return;            // override manuale: il sistema non vince
                applyTheme(!e.matches);
            };
            if (darkMq.addEventListener) darkMq.addEventListener('change', onSystemThemeChange);
            else if (darkMq.addListener) darkMq.addListener(onSystemThemeChange);
        }

        // Il "Quiz" casuale è stato sostituito dal Ripasso a ripetizione
        // spaziata (js/srs.js), che fa la stessa cosa ma in modo programmato.

        // ===== MAPPA CONCETTI (overlay panoramico, uniforme col sito) =====
        const graphOpenBtn = document.getElementById('graphOpenBtn');
        const cmapOverlay  = document.getElementById('cmapOverlay');
        const cmapBody     = document.getElementById('cmapBody');
        const cmapSummary  = document.getElementById('cmapSummary');
        const cmapSearch   = document.getElementById('cmapSearch');
        const cmapClose    = document.getElementById('cmapClose');
        const cmapSubjects = document.getElementById('cmapSubjects');
        let cmapSubject = 'agronomia';
        let cmapQuery = '';

        function cmapEsc(s) {
            return String(s).replace(/[&<>"']/g, function (c) {
                return { '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c];
            });
        }
        function cmapStatusClass(st) {
            if (st === 'review') return 's-review';
            if (st === 'progress') return 's-progress';
            if (st === 'done') return 's-done';
            return 's-todo';
        }

        // ── Difficoltà degli argomenti: manuale (assegnata) + indice automatico ──
        const TOPIC_DIFF_KEY = 'topic_difficulty_v1';
        const DIFF_LABELS = { 1: 'Facile', 2: 'Media', 3: 'Difficile' };
        let cmapSort = 'order';
        const cmapOpen = new Set();   // argomenti espansi (preservati tra i re-render)

        function loadTopicDiff() {
            try { return JSON.parse(localStorage.getItem(TOPIC_DIFF_KEY) || '{}'); } catch (e) { return {}; }
        }
        function getTopicDiff(subject, cat) {
            const d = loadTopicDiff();
            return (d[subject] && d[subject][cat]) || 0;
        }
        function setTopicDiff(subject, cat, level) {
            const d = loadTopicDiff();
            if (!d[subject]) d[subject] = {};
            if (level) d[subject][cat] = level; else delete d[subject][cat];
            localStorage.setItem(TOPIC_DIFF_KEY, JSON.stringify(d));   // intercettata dal sync -> "non salvato"
        }
        function loadSrsMap() {
            try { return JSON.parse(localStorage.getItem('srs_v1') || '{}'); } catch (e) { return {}; }
        }
        // Difficoltà SUGGERITA dai dati: 0 = nessun segnale, 1..3 (da "da ripassare"
        // e dalle schede deboli nel ripasso: facilità bassa o errori).
        function suggestedDifficulty(items, srs) {
            let review = 0, weak = 0;
            const total = items.length;
            items.forEach(function (x) {
                if ((studyStates[x.id] || 'todo') === 'review') review++;
                const e = srs[x.id];
                if (e && ((typeof e.ef === 'number' && e.ef < 2.0) || (e.lapses || 0) > 0)) weak++;
            });
            if (review === 0 && weak === 0) return 0;
            const ratio = total ? (review + weak) / total : 0;
            if (ratio >= 0.34) return 3;
            if (ratio >= 0.12) return 2;
            return 1;
        }

        function renderConceptMap() {
            if (!cmapBody) return;
            const cards = Array.prototype.slice.call(
                document.querySelectorAll('.card[data-subject="' + cmapSubject + '"]'));
            const groups = {};
            const order = [];
            cards.forEach(function (c) {
                const cat = c.getAttribute('data-category') || 'Altro';
                if (!groups[cat]) { groups[cat] = []; order.push(cat); }
                const t = c.querySelector('.card-title');
                groups[cat].push({ id: c.getAttribute('data-id'), title: t ? t.textContent.trim() : '(scheda)' });
            });
            let cats = order;
            if (cmapSubject === 'agronomia' && typeof cleanTopicOrder !== 'undefined') {
                cats = cleanTopicOrder.filter(function (c) { return groups[c]; })
                    .concat(order.filter(function (c) { return cleanTopicOrder.indexOf(c) < 0; }));
            }

            const srs = loadSrsMap();
            const stats = {};
            cats.forEach(function (cat, i) {
                const items = groups[cat];
                let dCount = 0;
                items.forEach(function (x) { if ((studyStates[x.id] || 'todo') === 'done') dCount++; });
                const manual = getTopicDiff(cmapSubject, cat);
                const suggested = suggestedDifficulty(items, srs);
                stats[cat] = {
                    order: i, done: dCount, total: items.length,
                    manual: manual, suggested: suggested,
                    attention: Math.max(manual, suggested),
                    mismatch: !!(manual && suggested && suggested > manual)
                };
            });

            if (cmapSort === 'difficulty') {
                cats = cats.slice().sort(function (a, b) {
                    return (stats[b].manual - stats[a].manual) ||
                           (stats[b].suggested - stats[a].suggested) ||
                           (stats[a].order - stats[b].order);
                });
            } else if (cmapSort === 'attention') {
                cats = cats.slice().sort(function (a, b) {
                    return (stats[b].attention - stats[a].attention) ||
                           ((stats[b].total - stats[b].done) - (stats[a].total - stats[a].done)) ||
                           (stats[a].order - stats[b].order);
                });
            }

            let total = 0, done = 0, attentionTopics = 0;
            cats.forEach(function (cat) {
                total += stats[cat].total; done += stats[cat].done;
                if (stats[cat].attention >= 2) attentionTopics++;
            });
            const pct = total ? Math.round(done / total * 100) : 0;
            if (cmapSummary) {
                cmapSummary.innerHTML =
                    '<span><strong>' + done + '</strong> / ' + total + ' concetti imparati</span>' +
                    '<span class="cmap-summary-bar"><span style="width:' + pct + '%"></span></span>' +
                    '<strong>' + pct + '%</strong>' +
                    (attentionTopics ? '<span class="cmap-attn-summary" title="Argomenti con difficoltà alta o segnalati dai tuoi dati">' + attentionTopics + ' da attenzionare</span>' : '');
            }

            cmapBody.innerHTML = '';
            let anyVisible = false;
            cats.forEach(function (cat) {
                const items = groups[cat];
                const filtered = cmapQuery
                    ? items.filter(function (x) { return x.title.toLowerCase().indexOf(cmapQuery) >= 0; })
                    : items;
                if (!filtered.length) return;
                anyVisible = true;

                const st = stats[cat];
                const tpct = Math.round(st.done / st.total * 100);
                const hex = (typeof hexTagColors !== 'undefined' && hexTagColors[cat]) || '#14b8a6';

                const concepts = filtered.map(function (x) {
                    const cls = cmapStatusClass(studyStates[x.id] || 'todo');
                    return '<button class="cmap-concept" type="button" data-id="' + cmapEsc(x.id) + '">' +
                        '<span class="status-dot ' + cls + '"></span>' +
                        '<span class="cmap-concept-title">' + cmapEsc(x.title) + '</span></button>';
                }).join('');

                const diffLabel = st.manual ? DIFF_LABELS[st.manual] : 'Difficoltà';
                const diffChip = '<button class="cmap-diff diff-' + (st.manual || 0) + '" type="button" ' +
                    'title="Difficoltà percepita — clicca per cambiare">' + diffLabel + '</button>';
                let attn = '';
                if (st.suggested >= 2) {
                    const tip = st.mismatch
                        ? 'I tuoi dati indicano una difficoltà maggiore di quella impostata (consigliato: ' + DIFF_LABELS[st.suggested] + ').'
                        : 'I tuoi dati indicano che qui fai più fatica (consigliato: ' + DIFF_LABELS[st.suggested] + ').';
                    attn = '<span class="cmap-attn' + (st.mismatch ? ' is-mismatch' : '') + '" title="' + tip + '">!</span>';
                }

                const topic = document.createElement('div');
                topic.className = 'cmap-topic' + ((cmapQuery || cmapOpen.has(cat)) ? ' is-open' : '');
                topic.style.setProperty('--cat', hex);
                topic.innerHTML =
                    '<div class="cmap-topic-head" role="button" tabindex="0" aria-expanded="' + ((cmapQuery || cmapOpen.has(cat)) ? 'true' : 'false') + '">' +
                        '<span class="cmap-topic-dot"></span>' +
                        '<span class="cmap-topic-name">' + cmapEsc(cat) + '</span>' +
                        attn +
                        diffChip +
                        '<span class="cmap-topic-count">' + st.done + '/' + st.total + '</span>' +
                        '<span class="cmap-topic-bar"><span style="width:' + tpct + '%"></span></span>' +
                        '<span class="cmap-topic-chevron">&#9662;</span>' +
                    '</div>' +
                    '<div class="cmap-concepts">' + concepts + '</div>';

                const head = topic.querySelector('.cmap-topic-head');
                function toggleTopic() {
                    const open = topic.classList.toggle('is-open');
                    head.setAttribute('aria-expanded', open ? 'true' : 'false');
                    if (open) cmapOpen.add(cat); else cmapOpen.delete(cat);
                }
                head.addEventListener('click', function (e) {
                    if (e.target.closest('.cmap-diff')) return;   // il chip difficoltà gestisce il suo click
                    toggleTopic();
                });
                head.addEventListener('keydown', function (e) {
                    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleTopic(); }
                });
                head.querySelector('.cmap-diff').addEventListener('click', function (e) {
                    e.stopPropagation();
                    setTopicDiff(cmapSubject, cat, (st.manual + 1) % 4);   // cicla 0->1->2->3->0
                    renderConceptMap();
                });
                topic.querySelectorAll('.cmap-concept').forEach(function (btn) {
                    btn.addEventListener('click', function () { navigateToConcept(btn.getAttribute('data-id')); });
                });
                cmapBody.appendChild(topic);
            });

            if (!anyVisible) {
                cmapBody.innerHTML = '<div class="cmap-empty"><h4>Nessun concetto trovato</h4><p>Prova con un\'altra parola chiave.</p></div>';
            }
        }

        window.navigateToConcept = function (cardId) {
            closeConceptMap();
            const cardEl = document.getElementById('card_' + cardId);
            if (!cardEl) return;
            const subj = cardEl.getAttribute('data-subject') || 'agronomia';
            // azzera i filtri rapidi per non nascondere la card
            currentStudyFilter = 'all';
            try { Object.values(quickFilters).forEach(function (f) { if (f) f.classList.remove('active'); }); } catch (e) {}
            if (typeof switchSubject === 'function') switchSubject(subj);
            playAudioTone(523.25, 'sine', 0.1);
            setTimeout(function () {
                cardEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
                cardEl.classList.remove('active-recall-hidden');
                cardEl.classList.remove('card-pulse-active');
                void cardEl.offsetWidth;
                cardEl.classList.add('card-pulse-active');
                setTimeout(function () { cardEl.classList.remove('card-pulse-active'); }, 3000);
            }, 90);
        };

        function openConceptMap() {
            if (!cmapOverlay) return;
            cmapQuery = '';
            cmapOpen.clear();
            cmapSort = 'order';
            if (cmapSearch) cmapSearch.value = '';
            const sortSel = document.getElementById('cmapSort');
            if (sortSel) sortSel.value = 'order';
            cmapSubject = (typeof activeSubject !== 'undefined' && activeSubject) ? activeSubject : 'agronomia';
            if (['agronomia', 'biologia', 'botanica'].indexOf(cmapSubject) < 0) cmapSubject = 'agronomia';
            if (cmapSubjects) cmapSubjects.querySelectorAll('.cmap-subj').forEach(function (b) {
                b.classList.toggle('active', b.getAttribute('data-subject') === cmapSubject);
            });
            renderConceptMap();
            cmapOverlay.classList.add('is-open');
            document.documentElement.classList.add('modal-open');   // blocca lo scroll della pagina
            playAudioTone(880, 'sine', 0.12);
        }
        function closeConceptMap() {
            if (!cmapOverlay) return;
            cmapOverlay.classList.remove('is-open');
            document.documentElement.classList.remove('modal-open');
        }

        if (graphOpenBtn) graphOpenBtn.addEventListener('click', openConceptMap);
        if (cmapClose) cmapClose.addEventListener('click', closeConceptMap);
        if (cmapOverlay) cmapOverlay.addEventListener('click', function (e) { if (e.target === cmapOverlay) closeConceptMap(); });
        document.addEventListener('keydown', function (e) {
            if (e.key === 'Escape' && cmapOverlay && cmapOverlay.classList.contains('is-open')) closeConceptMap();
        });
        if (cmapSearch) cmapSearch.addEventListener('input', function (e) {
            cmapQuery = e.target.value.toLowerCase().trim();
            renderConceptMap();
        });
        if (cmapSubjects) cmapSubjects.querySelectorAll('.cmap-subj').forEach(function (b) {
            b.addEventListener('click', function () {
                cmapSubject = b.getAttribute('data-subject');
                cmapOpen.clear();
                cmapSubjects.querySelectorAll('.cmap-subj').forEach(function (x) { x.classList.toggle('active', x === b); });
                renderConceptMap();
            });
        });
        const cmapSortSel = document.getElementById('cmapSort');
        if (cmapSortSel) cmapSortSel.addEventListener('change', function () {
            cmapSort = cmapSortSel.value;
            renderConceptMap();
        });

        // Initialize study state on load
        // loadState(); delayed to initUnifiedApp()
    
