        let activeBotDivision = "all";


        // ==========================================================================
        // 🧬 BIOLOGIA & ISTOLOGIA CONTROLLER
        // ==========================================================================
        function initUnifiedApp() {
            // Load state now that all let variables are initialized to avoid TDZ ReferenceError
            if (typeof loadState === "function") loadState();

            buildCardSections();      // intestazioni di argomento tra le schede
            updateSectionHeaders();

            renderBioSidebar();
            renderTaxonomyGrid();
            
            // Setup click listeners for recall blocks that are loaded in content cards!
            document.addEventListener('click', (e) => {
                const recallBlock = e.target.closest('.recall-block');
                if (recallBlock) {
                    recallBlock.classList.toggle('revealed');
                    playAudioTone(1000, 'sine', 0.08);
                }
            });
            
            // Run default stats load
            setTimeout(() => {
                updateTrackerStats();
                renderDashboardRoadmap();
            }, 100);
        }

        function renderBioSidebar() {
            const sidebar = document.getElementById("cellLabIndex");
            if (!sidebar) return;
            sidebar.innerHTML = "";
            
            const groups = {
                "biologia_generale": "🧬 BIOLOGIA GENERALE",
                "istologia_vegetale": "🔬 ISTOLOGIA VEGETALE",
                "anatomia_vegetale": "🌿 ANATOMIA VEGETALE",
                "fisiologia_vegetale": "☀ FISIOLOGIA VEGETALE"
            };
            
            let currentGroup = "";
            
            Object.keys(cellLabData).forEach(key => {
                const topic = cellLabData[key];
                
                if (topic.group && topic.group !== currentGroup) {
                    currentGroup = topic.group;
                    const groupTitle = document.createElement("div");
                    groupTitle.className = "cell-sidebar-group-title";
                    groupTitle.textContent = groups[currentGroup] || currentGroup.toUpperCase();
                    sidebar.appendChild(groupTitle);
                }
                
                const btn = document.createElement("button");
                btn.className = `cell-lab-btn ${key === activeBioTopic ? 'active' : ''}`;
                btn.innerHTML = `${topic.title}`;
                
                btn.onclick = () => {
                    activeBioTopic = key;
                    renderBioSidebar();
                    renderBioContent();
                    playAudioTone(900, 'sine', 0.05);
                };
                
                sidebar.appendChild(btn);
            });
        }

